<template><div class="toolbar"><el-input v-model="q" placeholder="输入关键字查询"/><el-button @click="load">查询</el-button><el-button type="primary" @click="open()">新建</el-button></div><el-table :data="rows" border><el-table-column prop="name" label="名称"/><el-table-column prop="code" label="编码" v-if="type==='regions'"/><el-table-column prop="regionName" label="所属区域" v-if="type==='orgs'"/><el-table-column prop="desc" label="描述"/><el-table-column label="操作"><template #default="s"><el-button @click="open(s.row)">修改</el-button><el-button type="danger" @click="del(s.row.id)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="show" title="编辑"><el-form :model="form"><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="编码" v-if="type==='regions'"><el-input v-model="form.code"/></el-form-item><el-form-item label="所属区域" v-if="type==='orgs'"><el-select v-model="form.regionId"><el-option v-for="r in regions" :label="r.name" :value="r.id"/></el-select></el-form-item><el-form-item label="描述"><el-input v-model="form.desc"/></el-form-item></el-form><template #footer><el-button type="primary" @click="save">保存</el-button></template></el-dialog></template>
<script setup>import{ref,onMounted,watch}from'vue';import{useRoute}from'vue-router';import{api}from'../api/http';const route=useRoute(),type=ref(route.meta.type),rows=ref([]),regions=ref([]),q=ref(''),show=ref(false),form=ref({});const user=JSON.parse(localStorage.getItem('user'));async function load(){type.value=route.meta.type;rows.value=(await api.get('/'+type.value,{params:{q:q.value}})).data;if(type.value==='orgs')regions.value=(await api.get('/regions')).data}function open(r={}){form.value={...r};show.value=true}async function save(){const data={...form.value,username:user.username};form.value.id?await api.put(`/${type.value}/${form.value.id}`,data):await api.post('/'+type.value,data);show.value=false;load()}async function del(id){await api.delete(`/${type.value}/${id}`,{params:{username:user.username}});load()}onMounted(load);watch(()=>route.meta.type,load)</script>
